CREATE TABLE IF NOT EXISTS users (id VARCHAR(64) COLLATE utf8mb4_unicode_ci PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(190) NOT NULL UNIQUE,phone VARCHAR(40) NOT NULL DEFAULT '',role ENUM('customer','manager','root') NOT NULL DEFAULT 'customer',password_hash CHAR(128) NOT NULL,password_salt CHAR(32) NOT NULL,created_at DATETIME(3) NOT NULL,updated_at DATETIME(3) NULL,INDEX idx_users_role(role)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS sessions (token_hash CHAR(64) COLLATE utf8mb4_unicode_ci PRIMARY KEY,user_id VARCHAR(64) COLLATE utf8mb4_unicode_ci NOT NULL,expires_at DATETIME(3) NOT NULL,created_at DATETIME(3) NOT NULL,CONSTRAINT fk_sessions_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,INDEX idx_sessions_user(user_id),INDEX idx_sessions_expiry(expires_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS products (id VARCHAR(96) COLLATE utf8mb4_unicode_ci PRIMARY KEY,name VARCHAR(255) NOT NULL,category VARCHAR(120) NOT NULL,price INT UNSIGNED NOT NULL,weight INT UNSIGNED NOT NULL,kcal INT UNSIGNED NOT NULL,rating DECIMAL(3,2) NOT NULL,payload_json JSON NOT NULL,updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,INDEX idx_products_category(category),FULLTEXT KEY ftx_products(name)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS orders (id VARCHAR(64) COLLATE utf8mb4_unicode_ci PRIMARY KEY,user_id VARCHAR(64) COLLATE utf8mb4_unicode_ci NULL,customer_name VARCHAR(120) NOT NULL,phone VARCHAR(40) NOT NULL,email VARCHAR(190) NOT NULL DEFAULT '',address VARCHAR(500) NOT NULL,comment TEXT NOT NULL,delivery VARCHAR(100) NOT NULL,payment VARCHAR(100) NOT NULL,total INT UNSIGNED NOT NULL,status ENUM('Принят','Подтверждён','Готовится','Готов','В доставке','Доставлен','Отменён') NOT NULL DEFAULT 'Принят',created_at DATETIME(3) NOT NULL,updated_at DATETIME(3) NULL,CONSTRAINT fk_orders_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL,INDEX idx_orders_user(user_id),INDEX idx_orders_status(status),INDEX idx_orders_created(created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS order_items (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,order_id VARCHAR(64) COLLATE utf8mb4_unicode_ci NOT NULL,product_id VARCHAR(96) COLLATE utf8mb4_unicode_ci NOT NULL,name VARCHAR(255) NOT NULL,price INT UNSIGNED NOT NULL,quantity SMALLINT UNSIGNED NOT NULL,CONSTRAINT fk_items_order FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE,INDEX idx_items_order(order_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS leads (id VARCHAR(64) COLLATE utf8mb4_unicode_ci PRIMARY KEY,name VARCHAR(120) NOT NULL DEFAULT '',phone VARCHAR(40) NOT NULL,email VARCHAR(190) NOT NULL DEFAULT '',message TEXT NOT NULL,source VARCHAR(120) NOT NULL DEFAULT '',created_at DATETIME(3) NOT NULL,INDEX idx_leads_created(created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS root_audit_log (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,root_user_id VARCHAR(64) COLLATE utf8mb4_unicode_ci NOT NULL,action VARCHAR(120) NOT NULL,entity_type VARCHAR(80) NOT NULL,entity_id VARCHAR(96) COLLATE utf8mb4_unicode_ci NOT NULL,payload_json JSON NULL,created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,INDEX idx_audit_root(root_user_id),INDEX idx_audit_entity(entity_type,entity_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
